for ln = splitlines(montageRaw)'
    str = strtrim(ln{1});
    if str == "" || startsWith(str,"%")
        continue; end
    parts = split(str,":");
    if numel(parts) < 2, continue; end
    key   = strtrim(parts(1));
    chans = strtrim(parts(2));
    %     roiDefs(char(key)) = cellstr(split(chans,"|"));
    roiDefs(char(key)) = cellstr(strtrim(split(chans,"|")));
end

roiNames = [{'Manual'} sort(roiDefs.keys)];
end

